// Generated by Selenium IDE
const { Builder, By, Key, until } = require('selenium-webdriver');
const assert = require('assert');

describe('F4 list department pro skill', function () {
  this.timeout(30000);
  let driver;
  let vars;
  beforeEach(async function () {
    driver = await new Builder().forBrowser('chrome').usingServer('http://localhost:4444/wd/hub').build();
    vars = {};
  });
  afterEach(async function () {
    await driver.quit();
  });
  it('F4 list department pro skill', async function () {
    await driver.get('http://localhost:4200/home');
    await driver.manage().window().setRect({ width: 1936, height: 1056 });
    await driver.findElement(By.css('.ant-row:nth-child(5) .ant-card-body')).click();
    await driver.findElement(By.xpath("//div[@id='root']/section/section/header/ul/li[2]/span")).click();
    await driver.findElement(By.css('.ant-btn-primary > span')).click();
    {
      const element = await driver.findElement(By.css('.ant-btn-primary > span'));
      await driver.actions({ bridge: true }).moveToElement(element).perform();
    }
    {
      const element = await driver.findElement(By.CSS_SELECTOR, 'body');
      await driver.actions({ bridge: true }).moveToElement(element, 0, 0).perform();
    }
    assert((await driver.findElement(By.css('.ant-typography:nth-child(1)')).getText()) == '公開専門スキル一覧');
    assert((await driver.findElement(By.css('.ant-form-item-no-colon')).getText()) == '部署');
    assert((await driver.findElement(By.css('.ant-table-thead .ant-table-cell:nth-child(1)')).getText()) == '部署');
    assert(
      (await driver.findElement(By.css('.ant-table-thead .ant-table-cell:nth-child(2)')).getText()) == 'バージョン',
    );
    assert(
      (await driver.findElement(By.css('.ant-table-thead .ant-table-cell:nth-child(3)')).getText()) == '最終更新者',
    );
    assert(
      (await driver.findElement(By.css('.ant-table-thead .ant-table-cell:nth-child(4)')).getText()) == '最終更新日	',
    );
    assert((await driver.findElement(By.css('.ant-table-thead .ant-table-cell:nth-child(5)')).getText()) == '公開日');
  });
});
